try {
const CK='ck_e5baa5ce61b37009731cdaaac1c6509996c47754';
const CS='cs_f1e5dcd8da0d11fafe5b546ead0f76eaf4063d2a';
const BASE='https://www.atelierlanonna.com/wp-json/wc/v3/orders';
const SUPA='https://jtqfxakabthzakmhncrw.supabase.co/rest/v1/pedidos_woo';
const KEY='sb_publishable_Wr-dnT92OLrYWsqhTrr4mw_F88RdJ2p';

const anyo=new Date().getFullYear();
const after=`${anyo}-01-01T00:00:00`;

// 1. Paginar WooCommerce
let page=1, all=[];
while(true){
  const data=await $helpers.httpRequest({
    method:'GET',
    url:`${BASE}?consumer_key=${CK}&consumer_secret=${CS}&per_page=100&page=${page}&status=any&after=${after}`
  });
  if(!Array.isArray(data)||data.length===0) break;
  all=all.concat(data);
  if(data.length<100) break;
  page++;
}

// 2. Transformar
const rows=all.map(o=>({
  woo_id:o.id,
  numero:String(o.number),
  fecha:(o.date_paid||o.date_created||'').slice(0,10)||null,
  cliente_nombre:((o.billing?.first_name||'')+' '+(o.billing?.last_name||'')).trim(),
  cliente_email:o.billing?.email||'',
  total:parseFloat(o.total)||0,
  estado:o.status,
  lineas:(o.line_items||[]).map(li=>li.name).join(', ')
}));

// 3. Upsert en Supabase (lotes de 100)
for(let i=0;i<rows.length;i+=100){
  await $helpers.httpRequest({
    method:'POST',
    url:SUPA+'?on_conflict=woo_id',
    headers:{
      'apikey':KEY,
      'Authorization':'Bearer '+KEY,
      'Content-Type':'application/json',
      'Prefer':'resolution=merge-duplicates'
    },
    body:rows.slice(i,i+100),
    json:true
  });
}

return [{json:{success:true,total:rows.length,anyo,paginas:page-1}}];
} catch(err) {
  return [{json:{success:false,error:err.message}}];
}
